kernel void cl_fdwt53Kernel(const int *input, int *output,
                            const int sizeX, const int sizeY,
                            const int steps,
                            const int WIN_SX, const int WIN_SY)
{
    const int WIN_SIZE_X = WIN_SX;
    const int WIN_SIZE_Y = WIN_SY;

    const int VERTICAL_STRIDE = 2 + (WIN_SIZE_X / 2);
    const int BUFFER_SIZE = VERTICAL_STRIDE * (WIN_SIZE_Y + 3);
    const int SHM_BANKS = 16;
    const int PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS);
    const int ODD_OFFSET = BUFFER_SIZE + PADDING;

    __local int data[2 * BUFFER_SIZE + PADDING];

    int threadIdx_x = get_local_id(0);
    int blockIdx_x = get_group_id(0);
    int blockIdx_y = get_group_id(1);

    const int firstY = blockIdx_y * WIN_SIZE_Y * steps;
    const int firstX = blockIdx_x * WIN_SIZE_X + threadIdx_x;

    if (firstX >= sizeX || firstY >= sizeY) {
        return;
    }

    int columnOffset = threadIdx_x + 2;
    columnOffset = columnOffset / 2 + (columnOffset & 1) * ODD_OFFSET;

    int loaderIndex = firstX + sizeX * firstY;

    int pixel0 = input[loaderIndex];
    int pixel1 = input[loaderIndex + sizeX];
    int pixel2 = input[loaderIndex + 2 * sizeX];

    data[columnOffset + 0 * VERTICAL_STRIDE] = pixel0;
    data[columnOffset + 1 * VERTICAL_STRIDE] = pixel1;
    data[columnOffset + 2 * VERTICAL_STRIDE] = pixel2;

    for (int i = 3; i < (3 + WIN_SIZE_Y); i++) {
        int loadIndex = firstX + sizeX * (firstY + i);
        if (loadIndex < sizeX * sizeY) {
            data[columnOffset + i * VERTICAL_STRIDE] = input[loadIndex];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);

    for (int r = 0; r < WIN_SIZE_Y; r += 2) {
        int rowIdx = 2 + r;
        if (rowIdx < WIN_SIZE_Y + 3) {
            int centerIdx = columnOffset + rowIdx * VERTICAL_STRIDE;
            int prevIdx = columnOffset + (rowIdx - 1) * VERTICAL_STRIDE;
            int nextIdx = columnOffset + (rowIdx + 1) * VERTICAL_STRIDE;

            if (prevIdx < 2 * BUFFER_SIZE + PADDING && centerIdx < 2 * BUFFER_SIZE + PADDING && nextIdx < 2 * BUFFER_SIZE + PADDING) {
                data[centerIdx] -= (data[prevIdx] + data[nextIdx]) / 2;
            }
        }
    }

